parameters.jsCode:
const inputData = $input.first().json;

// Map Smartlead event types to our activity types
const eventTypeMap = {
  'EMAIL_SENT': 'sent',
  'EMAIL_OPEN': 'opened',
  'EMAIL_LINK_CLICK': 'clicked',
  'EMAIL_REPLY': 'replied',
  'EMAIL_BOUNCE': 'bounced',
  'LEAD_UNSUBSCRIBED': 'unsubscribed',
  'LEAD_CATEGORY_UPDATED': 'status_changed'
};

const mappedActivityType = eventTypeMap[inputData.event_type] || inputData.event_type;

// Determine if this is an engagement event (for updating first_engagement_at)
const isEngagementEvent = ['opened', 'clicked', 'replied'].includes(mappedActivityType);

// Determine if this is a reply event
const isReplyEvent = mappedActivityType === 'replied';

// Determine if this should pause the contact
const isPauseEvent = ['bounced', 'unsubscribed'].includes(mappedActivityType);

// Determine engagement level based on event
let engagementLevel = null;
if (mappedActivityType === 'opened') engagementLevel = 'warm';
if (mappedActivityType === 'clicked') engagementLevel = 'engaged';
if (mappedActivityType === 'replied') engagementLevel = 'hot';

return [{
  json: {
    ...inputData,
    mapped_activity_type: mappedActivityType,
    is_engagement_event: isEngagementEvent,
    is_reply_event: isReplyEvent,
    is_pause_event: isPauseEvent,
    engagement_level_update: engagementLevel
  }
}];

// Merge contact data from lookup
const eventData = $('Map Event Types').first().json;
const contactResult = $input.first().json;

// Contact data comes as array from Postgres node
let contact;
if (Array.isArray(contactResult)) {
  contact = contactResult[0];
} else if (contactResult && contactResult.id) {
  contact = contactResult;
} else {
  contact = null;
}

return [{
  json: {
    ...eventData,
    contact_id: contact?.id || null,
    contact_email: contact?.email || eventData.to_email,
    contact_first_name: contact?.first_name || '',
    contact_last_name: contact?.last_name || '',
    contact_linkedin_url: contact?.linkedin_url || ''
  }
}];

const eventData = $('Merge Contact Data').first().json;
const contextResult = $('Get Campaign Context').first().json;

// Handle array response from Postgres
const ctx = Array.isArray(contextResult) ? contextResult[0] : contextResult;

return [{
  json: {
    ...eventData,
    campaign_contact_id: ctx?.campaign_contact_id || null,
    campaign_contact_channel_id: ctx?.campaign_contact_channel_id || null,
    campaign_channel_id: ctx?.campaign_channel_id || 'cc222222-3333-4444-5555-666677778888'
  }
}];

const eventData = $('Merge Campaign Context').first().json;

// Map Smartlead lead categories to our intent classifications
// Common Smartlead categories: Interested, Not Interested, Out of Office, 
// Wrong Person, Unsubscribed, Auto Reply, Meeting Request, etc.
const categoryLower = (eventData.lead_category_new || '').toLowerCase();

let triggerEvent = null;
let suggestedBranch = null;
let shouldOptOut = false;
let shouldPause = false;

// Map category to action
if (categoryLower.includes('interested') && !categoryLower.includes('not')) {
  triggerEvent = 'positive_reply';
  suggestedBranch = 'A';
} else if (categoryLower.includes('meeting') || categoryLower.includes('demo') || categoryLower.includes('call')) {
  triggerEvent = 'positive_reply';
  suggestedBranch = 'A';
} else if (categoryLower.includes('not interested') || categoryLower.includes('not_interested')) {
  triggerEvent = 'not_interested';
  shouldOptOut = true;
} else if (categoryLower.includes('wrong person') || categoryLower.includes('wrong_person')) {
  triggerEvent = 'wrong_person';
  shouldPause = true;
} else if (categoryLower.includes('out of office') || categoryLower.includes('ooo') || categoryLower.includes('auto reply')) {
  // Just log, no action
  triggerEvent = 'auto_reply';
} else if (categoryLower.includes('unsubscribe')) {
  triggerEvent = 'unsubscribe';
  shouldOptOut = true;
} else if (categoryLower.includes('maybe') || categoryLower.includes('later') || categoryLower.includes('not now')) {
  triggerEvent = 'not_now_polite';
  suggestedBranch = 'B';
}

return [{
  json: {
    ...eventData,
    lead_category_trigger_event: triggerEvent,
    lead_category_suggested_branch: suggestedBranch,
    lead_category_should_opt_out: shouldOptOut,
    lead_category_should_pause: shouldPause
  }
}];

const eventData = $('Merge Campaign Context').first().json;

// Smartlead's reply_category often contains intent:
// Common values: Interested, Not Interested, Out of Office, Wrong Person, etc.
const replyCategory = (eventData.reply_category || '').toLowerCase();
const replyText = eventData.reply_text || '';

let classification = 'neutral';
let triggerEvent = null;
let suggestedBranch = null;
let shouldOptOut = false;

// First, try to classify from reply_category if present
if (replyCategory) {
  if (replyCategory.includes('interested') && !replyCategory.includes('not')) {
    classification = 'positive_reply';
    triggerEvent = 'positive_reply';
    suggestedBranch = 'A';
  } else if (replyCategory.includes('not interested') || replyCategory.includes('not_interested')) {
    classification = 'not_interested';
    triggerEvent = 'not_interested';
    shouldOptOut = true;
  } else if (replyCategory.includes('out of office') || replyCategory.includes('ooo') || replyCategory.includes('auto')) {
    classification = 'auto_reply';
    // No action for auto-replies
  } else if (replyCategory.includes('wrong')) {
    classification = 'wrong_person';
    shouldOptOut = true;
  } else if (replyCategory.includes('unsubscribe') || replyCategory.includes('remove')) {
    classification = 'unsubscribe';
    triggerEvent = 'unsubscribe';
    shouldOptOut = true;
  } else if (replyCategory.includes('meeting') || replyCategory.includes('call') || replyCategory.includes('demo')) {
    classification = 'positive_reply';
    triggerEvent = 'positive_reply';
    suggestedBranch = 'A';
  } else if (replyCategory.includes('maybe') || replyCategory.includes('later') || replyCategory.includes('not now') || replyCategory.includes('busy')) {
    classification = 'not_now_polite';
    triggerEvent = 'not_now_polite';
    suggestedBranch = 'B';
  }
}

// If no clear classification from category, we could use AI here
// For now, default to neutral which won't trigger any branch assignment

return [{
  json: {
    ...eventData,
    classification: classification,
    trigger_event: triggerEvent,
    suggested_branch: suggestedBranch,
    is_opt_out: shouldOptOut,
    needs_ai_classification: !replyCategory && replyText.length > 0
  }
}];

